class Solution:
    def magicalString(self, n: int) -> int:
        s = [1, 2, 2]
        i = 2
        while len(s) < n:
            next_num = 3 - s[i-1]
            s.extend([next_num] * s[i])
            i += 1
        return s[:n].count(1)

